SELECT b.BOARD_ID, b.BOARD_CATEGORY, b.BOARD_TITLE, b.BOARD_HIT, b.BOARD_DATE, b.MEMBER_ID, m.MEMBER_LOGINID FROM BOARD b JOIN MEMBER m ON b.MEMBER_ID = m.MEMBER_ID
(b.BOARD_TITLE LIKE CONCAT('%', #{keyword}, '%') OR m.MEMBER_LOGINID LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY b.BOARD_ID DESC LIMIT #{size} OFFSET #{offset}

SELECT b.BOARD_ID, b.BOARD_CATEGORY, b.BOARD_TITLE, b.BOARD_HIT, b.BOARD_DATE, b.MEMBER_ID, m.MEMBER_LOGINID FROM BOARD b JOIN MEMBER m ON b.MEMBER_ID = m.MEMBER_ID WHERE b.BOARD_CATEGORY = #{category}
(b.BOARD_TITLE LIKE CONCAT('%', #{keyword}, '%') OR m.MEMBER_LOGINID LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY b.BOARD_ID DESC LIMIT #{size} OFFSET #{offset}
